using System.Numerics;
using UniswapSharp.Core.Entities;
using UniswapSharp.V3;
using UniswapSharp.V3.Entities;
using UniswapSharp.V3.Utils;
using static UniswapSharp.V3.Constants;
using NFPM = UniswapSharp.V3.NonfungiblePositionManager;

namespace UniswapSharp.Testing.V3;

// Ported from sdks/v3-sdk/src/staker.test.ts
public class StakerTests
{
    private static readonly Token reward = new(1, "0x1f9840a85d5aF5bf1D1762F925BDADdC4201F984", 18, "r", "reward");
    private static readonly Token token0 = new(1, "0x0000000000000000000000000000000000000001", 18, "t0", "token0");
    private static readonly Token token1 = new(1, "0x0000000000000000000000000000000000000002", 18, "t1", "token1");
    private static readonly Pool pool_0_1 = new(token0, token1, FeeAmount.MEDIUM, EncodeSqrtRatioX96.Encode(1, 1), 0, 0, new int[] { });

    private static readonly Staker.IncentiveKey incentiveKey = new() { RewardToken = reward, Pool = pool_0_1, StartTime = 100, EndTime = 200, Refundee = "0x0000000000000000000000000000000000000001" };
    private static readonly Staker.IncentiveKey incentiveKey2 = new() { RewardToken = reward, Pool = pool_0_1, StartTime = 50, EndTime = 100, Refundee = "0x0000000000000000000000000000000000000089" };
    private static readonly Staker.IncentiveKey[] incentiveKeys = { incentiveKey, incentiveKey2 };

    private const string recipient = "0x0000000000000000000000000000000000000003";
    private const string sender = "0x0000000000000000000000000000000000000004";
    private static readonly BigInteger tokenId = 1;

    [Fact]
    public void CollectRewards_WithAmount()
    {
        var r = Staker.CollectRewards(incentiveKey, new Staker.ClaimOptions { TokenId = tokenId, Recipient = recipient, Amount = 1 });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public void CollectRewards_NoAmount()
    {
        var r = Staker.CollectRewards(incentiveKey, new Staker.ClaimOptions { TokenId = tokenId, Recipient = recipient });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public void CollectRewards_MultipleKeys()
    {
        var r = Staker.CollectRewards(incentiveKeys, new Staker.ClaimOptions { TokenId = tokenId, Recipient = recipient });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public void WithdrawToken_OneKey()
    {
        var r = Staker.WithdrawToken(incentiveKey, new Staker.FullWithdrawOptions { TokenId = tokenId, Recipient = recipient, Amount = 0, Owner = sender, Data = "0x0000000000000000000000000000000000000008" });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public void WithdrawToken_MultipleKeys()
    {
        var r = Staker.WithdrawToken(incentiveKeys, new Staker.FullWithdrawOptions { TokenId = tokenId, Recipient = recipient, Amount = 0, Owner = sender, Data = "0x0000000000000000000000000000000000000008" });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public void EncodeDeposit_SingleKey() =>
        Assert.Equal("", Staker.EncodeDeposit(incentiveKey));

    [Fact]
    public void EncodeDeposit_MultipleKeys() =>
        Assert.Equal("", Staker.EncodeDeposit(incentiveKeys));

    [Fact]
    public void SafeTransferFrom_WithStakerData()
    {
        var r = NFPM.SafeTransferFromParameters(new NFPM.SafeTransferOptions { Sender = sender, Recipient = recipient, TokenId = tokenId, Data = Staker.EncodeDeposit(incentiveKey) });
        Assert.Equal("", r.Calldata);
        Assert.Equal("0x00", r.Value);
    }
}
